import logging
import logging.handlers
import os
from pathlib import Path

# Create log directory if it doesn't exist
log_directory = Path('/var/log/application')
log_directory.mkdir(parents=True, exist_ok=True)

# Define log format
detailed_formatter = logging.Formatter(
    fmt='%(asctime)s - %(name)s - %(levelname)s - [%(filename)s:%(lineno)d] - %(funcName)s() - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

simple_formatter = logging.Formatter(
    fmt='%(asctime)s - %(levelname)s - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

json_formatter = logging.Formatter(
    fmt='{"timestamp": "%(asctime)s", "level": "%(levelname)s", "logger": "%(name)s", "message": "%(message)s", "module": "%(module)s", "function": "%(funcName)s", "line": %(lineno)d}',
    datefmt='%Y-%m-%dT%H:%M:%S'
)

# Configure root logger
root_logger = logging.getLogger()
root_logger.setLevel(logging.DEBUG)

# Remove existing handlers
for handler in root_logger.handlers[:]:
    root_logger.removeHandler(handler)

# Main application log - rotating file handler (10MB per file, keep 10 backups)
main_handler = logging.handlers.RotatingFileHandler(
    filename=log_directory / 'application.log',
    maxBytes=10 * 1024 * 1024,  # 10MB
    backupCount=10,
    encoding='utf-8'
)
main_handler.setLevel(logging.INFO)
main_handler.setFormatter(detailed_formatter)
root_logger.addHandler(main_handler)

# Error log - rotating file handler (5MB per file, keep 20 backups)
error_handler = logging.handlers.RotatingFileHandler(
    filename=log_directory / 'error.log',
    maxBytes=5 * 1024 * 1024,  # 5MB
    backupCount=20,
    encoding='utf-8'
)
error_handler.setLevel(logging.ERROR)
error_handler.setFormatter(detailed_formatter)
root_logger.addHandler(error_handler)

# Debug log - time-based rotating file handler (daily rotation, keep 7 days)
debug_handler = logging.handlers.TimedRotatingFileHandler(
    filename=log_directory / 'debug.log',
    when='midnight',
    interval=1,
    backupCount=7,
    encoding='utf-8'
)
debug_handler.setLevel(logging.DEBUG)
debug_handler.setFormatter(detailed_formatter)
debug_handler.suffix = '%Y-%m-%d'
root_logger.addHandler(debug_handler)

# Access log - time-based rotating file handler (daily rotation, keep 30 days)
access_logger = logging.getLogger('access')
access_logger.setLevel(logging.INFO)
access_logger.propagate = False

